function buildCountryOptions() {
    var s1 = document.getElementById('inp-phone-code');
    var s2 = document.getElementById('inp-phone2-code');
    if(!s1 && !s2) return;

    if (s1) s1.innerHTML = '';
    if (s2) s2.innerHTML = '';

    countryCodes.forEach(function(c) {
        var flag = flagEmoji(c.iso);
        var label = flag + " " + c.iso + " " + c.c;

        var opt = document.createElement('option');
        opt.value = c.c;
        opt.setAttribute('data-len', c.l);
        opt.setAttribute('data-iso', c.iso);
        opt.textContent = label;
        if (c.c === "+90" && c.iso === "TR") opt.selected = true;

        if (s1) s1.appendChild(opt.cloneNode(true));
        if (s2) s2.appendChild(opt.cloneNode(true));
    });
}

function attachPhoneLengthLogic(selectId, inputId) {
    var sel = document.getElementById(selectId);
    var inp = document.getElementById(inputId);
    if(!sel || !inp) return;

    var applyLogic = function() {
        var opt = sel.options[sel.selectedIndex];
        var len = parseInt(opt.getAttribute('data-len'), 10) || 10;
        inp.setAttribute('maxlength', len);

        var currentLang = localStorage.getItem('gym_lang') || 'tr';
        if (currentLang === 'tr') {
            inp.placeholder = len + " haneli numara";
        } else {
            inp.placeholder = len + " digits number";
        }

        if(inp.value.length > len) {
            inp.value = inp.value.substring(0, len);
        }
    };

    inp.addEventListener('paste', function(e) {
        e.preventDefault();
        var pasted = (e.clipboardData || window.clipboardData).getData('text') || '';
        pasted = pasted.replace(/[^0-9]/g, '');
        var opt = sel.options[sel.selectedIndex];
        var len = parseInt(opt.getAttribute('data-len'), 10) || 10;
        inp.value = pasted.substring(0, len);
    });

    inp.addEventListener('input', function() {
        var val = inp.value.replace(/[^0-9]/g, '');
        var opt = sel.options[sel.selectedIndex];
        var len = parseInt(opt.getAttribute('data-len'), 10) || 10;
        if (val.length > len) val = val.substring(0, len);
        if (inp.value !== val) inp.value = val;
    });

    sel.addEventListener('change', applyLogic);
    applyLogic();
    return applyLogic;
}

var phoneLogic1, phoneLogic2;

document.addEventListener("DOMContentLoaded", function(event) {
    buildCountryOptions();
    phoneLogic1 = attachPhoneLengthLogic('inp-phone-code', 'inp-phone');
    phoneLogic2 = attachPhoneLengthLogic('inp-phone2-code', 'inp-phone2');

    var savedLang = localStorage.getItem('gym_lang') || 'tr';
    setLang(savedLang);
});

function setLang(lang) {
    localStorage.setItem('gym_lang', lang);
    var t = T[lang];
    var g = function(id) { return document.getElementById(id); };

    if(g('main-title')) g('main-title').textContent = t.title;
    if(g('main-sub')) g('main-sub').textContent = t.sub;
    if(g('tab-login')) g('tab-login').textContent = t.tabLogin;
    if(g('tab-register')) g('tab-register').textContent = t.tabRegister;

    if(g('lbl-name')) g('lbl-name').textContent = t.name;
    if(g('lbl-surname')) g('lbl-surname').textContent = t.surname;
    if(g('lbl-login-number')) g('lbl-login-number').textContent = t.number;
    if(g('lbl-reg-number')) g('lbl-reg-number').textContent = t.number;
    if(g('lbl-dept')) g('lbl-dept').textContent = t.dept;
    if(g('lbl-gender')) g('lbl-gender').textContent = t.gender;
    if(g('opt-gender-sel')) g('opt-gender-sel').textContent = t.genderSel;
    if(g('opt-male')) g('opt-male').textContent = t.male;
    if(g('opt-female')) g('opt-female').textContent = t.female;
    if(g('lbl-phone')) g('lbl-phone').textContent = t.phone;
    if(g('lbl-blood')) g('lbl-blood').textContent = t.blood;
    if(g('lbl-phone2')) g('lbl-phone2').textContent = t.phone2;
    if(g('lbl-address')) g('lbl-address').textContent = t.address;
    if(g('lbl-medical')) g('lbl-medical').textContent = t.medical;
    if(g('inp-medical')) g('inp-medical').placeholder = t.medicalPh;
    if(g('inp-login-number')) g('inp-login-number').placeholder = t.numberPh;
    if(g('inp-reg-number')) g('inp-reg-number').placeholder = t.numberPh;

    if(g('btn-login-submit')) g('btn-login-submit').textContent = t.loginSubmit;
    if(g('btn-reg-submit')) g('btn-reg-submit').textContent = t.regSubmit;
    if(g('btn-profile-checkout')) g('btn-profile-checkout').textContent = t.checkoutSubmit;

    if(g('lbl-prof-title')) g('lbl-prof-title').textContent = t.profTitle;
    if(g('lbl-prof-name')) g('lbl-prof-name').textContent = t.profName;
    if(g('lbl-prof-no')) g('lbl-prof-no').textContent = t.profNo;
    if(g('lbl-prof-dept')) g('lbl-prof-dept').textContent = t.profDept;
    if(g('lbl-prof-gender')) g('lbl-prof-gender').textContent = t.profGender;
    if(g('lbl-prof-blood')) g('lbl-prof-blood').textContent = t.profBlood;
    if(g('lbl-prof-phone')) g('lbl-prof-phone').textContent = t.profPhone;
    if(g('lbl-prof-phone2')) g('lbl-prof-phone2').textContent = t.profPhone2;
    if(g('lbl-prof-addr')) g('lbl-prof-addr').textContent = t.profAddr;
    if(g('lbl-prof-med')) g('lbl-prof-med').textContent = t.profMed;

    var genderValSpan = g('val-prof-gender');
    if(genderValSpan) {
        var rawGender = genderValSpan.getAttribute('data-gender');
        if(rawGender === 'male') genderValSpan.textContent = t.male;
        else if(rawGender === 'female') genderValSpan.textContent = t.female;
        else genderValSpan.textContent = '-';
    }

    if (phoneLogic1) phoneLogic1();
    if (phoneLogic2) phoneLogic2();

    var langInputs = document.getElementsByClassName('lang-input');
    for(var i=0; i<langInputs.length; i++) { langInputs[i].value = lang; }

    if(g('success-tr')) g('success-tr').style.display = lang === 'tr' ? 'block' : 'none';
    if(g('success-en')) g('success-en').style.display = lang === 'en' ? 'block' : 'none';
    if(g('reg-success-tr')) g('reg-success-tr').style.display = lang === 'tr' ? 'block' : 'none';
    if(g('reg-success-en')) g('reg-success-en').style.display = lang === 'en' ? 'block' : 'none';
    if(g('checkout-success-tr')) g('checkout-success-tr').style.display = lang === 'tr' ? 'block' : 'none';
    if(g('checkout-success-en')) g('checkout-success-en').style.display = lang === 'en' ? 'block' : 'none';

    if(g('btn-tr')) g('btn-tr').classList.toggle('active', lang === 'tr');
    if(g('btn-en')) g('btn-en').classList.toggle('active', lang === 'en');
}

function switchAuth(mode) {
    var g = function(id) { return document.getElementById(id); };
    var tabs = ['login', 'register'];
    tabs.forEach(function(tab) {
        if(g('form-' + tab)) g('form-' + tab).style.display = (mode === tab) ? 'block' : 'none';
        if(g('tab-' + tab)) {
            if (mode === tab) {
                g('tab-' + tab).classList.add('active');
            } else {
                g('tab-' + tab).classList.remove('active');
            }
        }
    });
}

function toggleProfileEdit() {
    var form = document.getElementById('profile-edit-form');
    var button = document.getElementById('btn-profile-edit');
    if (!form) return;

    var isHidden = form.style.display === 'none' || form.style.display === '';
    form.style.display = isHidden ? 'block' : 'none';
    if (button) button.textContent = isHidden ? 'Kapat' : 'Bilgileri Duzenle';
}


function updateTVTimers() {
    var clock = document.getElementById('live-clock');
    if (clock) clock.textContent = new Date().toLocaleTimeString('tr-TR');

    var timers = document.querySelectorAll('.countdown-timer');
    var now = new Date();
    timers.forEach(function(el) {
        var checkin = el.getAttribute('data-checkin');
        var allowed = parseInt(el.getAttribute('data-allowed'), 10);
        if(checkin && !isNaN(allowed)) {
            var isoStr = checkin.replace(' ', 'T');
            if (isoStr.indexOf('Z') === -1) isoStr += 'Z';

            var checkinDate = new Date(isoStr);
            var expireDate = new Date(checkinDate.getTime() + allowed * 60000);
            var diffMs = expireDate - now;

            if (diffMs <= 0) {
                el.innerHTML = '<span style="color: #dc2626; font-weight: 800;">00:00</span>';
            } else {
                var totalSecs = Math.floor(diffMs / 1000);
                var m = Math.floor(totalSecs / 60);
                var s = totalSecs % 60;
                m = m < 10 ? '0' + m : m;
                s = s < 10 ? '0' + s : s;
                el.innerHTML = '<span style="font-variant-numeric: tabular-nums;">' + m + ':' + s + '</span>';
            }
        }
    });
}

setInterval(updateTVTimers, 1000);
updateTVTimers();
